#include <stdio.h>
int main() {
    int T, n, m;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &n, &m);
        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        int max_len = 0;
        for (int i = 0; i < n; i++) {
            int len = 1;
            for (int j = i + 1; j < n; j++) {
                if (arr[j] >= arr[j - 1]) {
                    len++;
                } else {
                    break;
                }
            }
            max_len = (max_len > len) ? max_len : len;
        }
        printf("%d\n", max_len + m);
    }
    return 0;
}

