import sys
input = sys.stdin.readline
def solve():
    n, m = map(int, input().split())
    arr = list(map(int, input().split()))
    max_len = 0
    for i in range(n):
        len = 1
        for j in range(i + 1, n):
            if arr[j] >= arr[j - 1]:
                len += 1
            else:
                break
        max_len = max(max_len, len)
    print(max_len + m)
T = int(input())
for _ in range(T):
    solve()

